// Collect publishing results from all 3 stores
const product = $('📊 Read Products Ready to Publish').first().json;

const gumroadResult = $('🛒 Publish to Gumroad').first().json;
const etsyResult = $('🛒 Publish to Etsy').first().json;
const payhipResult = $('🛒 Publish to Payhip').first().json;

const publishReport = {
  product_id: product.Product_ID,
  title: product.Title,
  published_at: new Date().toISOString(),

  // Extract URLs from API responses
  gumroad_url: gumroadResult?.product?.short_url || gumroadResult?.product?.url || 'Check Gumroad Dashboard',
  gumroad_id: gumroadResult?.product?.id || null,
  gumroad_success: gumroadResult?.success === true,

  etsy_listing_id: etsyResult?.listing_id || null,
  etsy_url: etsyResult?.url || `https://www.etsy.com/listing/${etsyResult?.listing_id}`,
  etsy_success: !!etsyResult?.listing_id,

  payhip_url: payhipResult?.data?.link || 'Check Payhip Dashboard',
  payhip_id: payhipResult?.data?.id || null,
  payhip_success: !!payhipResult?.data,

  // Pass through social content for Workflow 4
  social_content: {
    ig_caption: product.IG_Caption,
    fb_post: product.FB_Post,
    tiktok_script: product.TikTok_Script,
    pinterest_description: product.Pinterest_Description,
    youtube_title: product.YouTube_Title,
    gumroad_url: gumroadResult?.product?.short_url || '',
    etsy_url: `https://www.etsy.com/listing/${etsyResult?.listing_id}` || '',
    payhip_url: payhipResult?.data?.link || ''
  },

  product_row_data: product
};

return [{ json: publishReport }];

// Check if WooCommerce is enabled in brand config
// Called after brand config is fetched (add WF06 call to start of WF03 if not present)
// For now: reads WC enabled flag from product sheet column

const product = $('📊 Read Products Ready to Publish').first().json;

// Check if WC is enabled — reads from brand config or sheet column
// Sheet column 'WC_Enabled' overrides brand config (for per-product control)
const wcEnabledSheet = product.WC_Enabled === 'YES' || product.WC_Enabled === 'true';
const wcEnabledGlobal = false; // ← This will be true when Phase 2 begins

// WC is enabled if either the global flag OR per-product flag is set
const wcEnabled = wcEnabledGlobal || wcEnabledSheet;

// Build WooCommerce product payload (ready for when enabled)
const wcPayload = {
  name: product.Title,
  type: 'simple',
  status: 'publish',
  featured: false,
  catalog_visibility: 'visible',
  description: product.Description_Long || product.Description || '',
  short_description: (product.Description || '').substring(0, 300),
  sku: `CSP-${product.Product_ID || Date.now()}`,
  regular_price: String(product.Price || '9.99'),

  // Digital product settings
  virtual: true,
  downloadable: true,
  download_limit: -1,      // Unlimited downloads
  download_expiry: -1,     // Never expire
  downloads: [
    {
      id: `dl-${product.Product_ID}`,
      name: product.Title,
      file: product.Drive_Download_URL || ''  // Google Drive public link
    }
  ],

  // SEO + discovery
  slug: (product.Title || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''),
  tags: (product.Tags || '').split(',').filter(Boolean).map(t => ({ name: t.trim() })),
  categories: [],  // Will be populated from brand config category_ids

  // Images (product mockup from creation workflow)
  images: product.Cover_Image_URL ? [
    { src: product.Cover_Image_URL, alt: product.Title }
  ] : [],

  // Meta for Yoast SEO on product pages
  meta_data: [
    { key: '_yoast_wpseo_focuskw', value: (product.Tags || '').split(',')[0]?.trim() || '' },
    { key: '_yoast_wpseo_metadesc', value: (product.Description || '').substring(0, 155) }
  ]
};

return [{ json: {
  wc_enabled: wcEnabled,
  wc_payload: wcPayload,
  product_id: product.Product_ID,
  product_title: product.Title,
  wc_domain: 'clearstackstudio.com',
  wc_api_version: 'wc/v3',
  _wc_prepared: true
}}];

// WooCommerce disabled — log the prepared payload for later
const prep = $input.first().json;
return [{ json: {
  wc_skipped: true,
  wc_enabled: false,
  wc_payload_saved: true,
  product_id: prep.product_id,
  message: 'WooCommerce disabled (Phase 2). Payload prepared and saved. Flip wcEnabledGlobal=true to activate.',
  wc_payload: prep.wc_payload
}}];
